import scala.collection.mutable

def solve(c: Long, connections: Array[Array[Long]], queries: Array[Array[Long]]): Array[Long] = {
  val parent = Array.fill(c + 1)(0)
  val rank = Array.fill(c + 1)(1)
  val inUse = Array.fill(c + 1)(true)

  def find(x: Long): Long = {
    if (parent(x) != x) parent(x) = find(parent(x))
    parent(x)
  }

  def union(x: Long, y: Long): Unit = {
    val fx = find(x)
    val fy = find(y)
    if (fx != fy) {
      if (rank(fx) > rank(fy)) {
        parent(fy) = fx
      } else {
        parent(fx) = fy
        if (rank(fx) == rank(fy)) rank(fy) += 1
      }
    }
  }

  for (i <- 1 to c) {
    parent(i) = i
  }

  for (conn <- connections) {
    val u = conn(0)
    val v = conn(1)
    union(u, v)
  }

  val result = mutable.ArrayBuffer[Long]()

  for (query <- queries) {
    val typeQ = query(0)
    val x = query(1)
    if (typeQ == 1) {
      if (inUse(x)) {
        result += x
      } else {
        val fx = find(x)
        var minId = -1
        for (i <- 1 to c) {
          if (inUse(i) && find(i) == fx) {
            if (minId == -1 || i < minId) minId = i
          }
        }
        result += minId
      }
    } else {
      inUse(x) = false
    }
  }

  result.toArray
}
